// Death #1 — ER=EPR matVec memoization, with Pisot-stabilized eviction.
//
// CONTEXT (FORMAL_LEDGER.md, sections "Topological Memoization &
// Pisot-Stabilized Intelligence" and "Buley-Llama Convergence"):
// every matmul output we have already computed sits in the cache as a
// pre-bridged endpoint of an Einstein-Rosen pair. When a new input
// arrives whose L²-distance to a cached input is below τ, we treat the
// cached output as ER-bridged into place: zero matmul, just teleport
// the bytes. The invariant we honor is
//
//     L²(input_a, input_b) ≤ τ      ⇒      ‖output_a − output_b‖ ≤ Lτ
//
// where L is the operator norm of the underlying weight matrix W. For
// quantized W (Q4K/Q6K) L is bounded; for F32 we treat L≈‖W‖₂. The
// caller is responsible for picking τ small enough that Lτ stays under
// the perplexity budget. We do not enforce that here.
// COVENANT: Lean theorem `MatVec.er_epr_bridge_bound` (unwritten) —
// a formal upper bound on output drift from input proximity.
//
// EVICTION POLICY: when capacity is hit we score every entry by
// `drift × age` (drift = distance from a Pisot-stable Lucas-trace
// surrogate; age = ticks since last_used). The argmax is dropped.
// Luminary states (drift ≈ 0 against the golden Pisot polynomial
// φ² − φ − 1 = 0) survive longest because their drift factor is near
// zero — `0 × age = 0` makes them un-evictable until something else
// is more drifted-and-stale. This is the discrete analogue of
// "low-energy attractors persist."
// COVENANT: Lean theorem `Pisot.luminary_persistence` (unwritten).
//
// IMPORTANT: this module is kept standalone. It does NOT call into
// `model.rs`. The caller passes the raw matvec dispatch as a function
// pointer (`raw_dispatch`) so the integration step can wire it without
// circular imports. The only crate-internal type we touch is
// `crate::model::QType` (the spec called it `crate::loader::QType` but
// the actual definition lives in `model.rs`; see integration notes).

use std::collections::HashMap;

// ───────────────────────── op-id constants ─────────────────────────
// u8, stable, append-only. New ops get the next free id; never
// renumber. Used as the second tuple component of the cache key so
// per-(layer, op) hit-rate breakdowns are meaningful.
pub const OP_Q: u8 = 0;
pub const OP_K: u8 = 1;
pub const OP_V: u8 = 2;
pub const OP_O: u8 = 3;
pub const OP_FFN_GATE: u8 = 4;
pub const OP_FFN_UP: u8 = 5;
pub const OP_FFN_DOWN: u8 = 6;
pub const OP_LM_HEAD: u8 = 7;
pub const OP_LM_HEAD_RANGE: u8 = 8;
pub const OP_LM_HEAD_PARTIAL: u8 = 9;
pub const OP_OUTPUT_PROJ: u8 = 10;
pub const OP_ATTENTION_SCORE: u8 = 11;
pub const OP_CTC_HEAD: u8 = 12;

// Golden ratio φ. The Pisot polynomial φ² − φ − 1 = 0 has the smallest
// Pisot number as its real root; its associated Lucas trace is the
// "stillest" sequence the cache can recognize. We use it as a stability
// reference: states whose `‖x‖² − φ‖x‖ + 1 ≈ 0` are Luminary and are
// preserved through eviction storms.
const PHI: f32 = 1.618_034;

// ───────────────────────── entry layout ─────────────────────────
struct MatVecMemoEntry {
    /// Probe key. Cloned from the caller's `&[f32]` at insert time.
    input: Vec<f32>,
    /// Compact `n_batch × rows` output (NO `out_stride` padding). The
    /// wrapper repacks it into the destination's stride on hit.
    output: Vec<f32>,
    /// Pisot-stable Lucas-trace surrogate. Vanishes at Luminary states.
    /// `(‖x‖² − φ‖x‖ + 1).abs()` — see eviction comment above.
    drift: f32,
    /// Monotone tick counter snapshot at last hit/insert. Used for LRU
    /// tie-breaking in the density eviction score.
    last_used: u64,
    /// Number of times this entry has been returned as a cache hit.
    /// Used in the liquid-memory density score: `(rows × cols) × (hit_count + 1)`.
    hit_count: u32,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
struct MatVecMemoKey {
    layer: usize,
    op: u8,
    rows: usize,
    cols: usize,
    qtype: u8,
    context_hash: u64,
}

// ───────────────────────── memo struct ─────────────────────────
pub struct MatVecMemo {
    /// Bucketed by operation identity and matmul shape. Probe scans only the
    /// relevant bucket, so per-layer-per-op working sets don't pollute each
    /// other, and range/partial lm_head calls cannot collide with full vocab
    /// calls that happen to share the same input vector.
    table: HashMap<MatVecMemoKey, Vec<MatVecMemoEntry>>,
    /// Per-key hit/miss counters for `detailed_stats`.
    per_key: HashMap<MatVecMemoKey, (u64, u64)>,
    enabled: bool,
    tau_squared: f32,
    /// Total entries across all buckets. We compare against
    /// `max_entries` to decide eviction.
    total_entries: usize,
    max_entries: usize,
    hits: u64,
    misses: u64,
    evictions: u64,
    /// LRU clock. Bumped on every probe + insert.
    tick: u64,
    /// Accumulated sum of evicted density scores: `(rows × cols) × (hit_count + 1)`.
    /// Tracks total "heat" released by the liquid-memory eviction policy.
    pub heat_released: u64,
}

impl MatVecMemo {
    pub fn new() -> Self {
        Self {
            table: HashMap::new(),
            per_key: HashMap::new(),
            enabled: false,
            // Default τ² is small but nonzero — exact-match-ish.
            // The integration step is expected to re-tune via
            // `set_tau_squared` once a calibration sweep lands.
            tau_squared: 1e-6,
            total_entries: 0,
            max_entries: 4096,
            hits: 0,
            misses: 0,
            evictions: 0,
            tick: 0,
            heat_released: 0,
        }
    }

    /// Memory pressure as a percentage of capacity: `(total_entries * 100) / max_entries`.
    /// Returns 0 when `max_entries` is 0 to avoid division by zero.
    pub fn memory_pressure(&self) -> u64 {
        if self.max_entries == 0 {
            return 0;
        }
        (self.total_entries as u64 * 100) / self.max_entries as u64
    }

    pub fn set_enabled(&mut self, on: bool) {
        self.enabled = on;
    }

    pub fn is_enabled(&self) -> bool {
        self.enabled
    }

    pub fn set_tau_squared(&mut self, tau_sq: f32) {
        self.tau_squared = tau_sq;
    }
    pub fn set_max_entries(&mut self, n: usize) {
        self.max_entries = n;
    }

    pub fn clear(&mut self) {
        self.table.clear();
        self.per_key.clear();
        self.total_entries = 0;
        self.hits = 0;
        self.misses = 0;
        self.evictions = 0;
        self.tick = 0;
        self.heat_released = 0;
    }

    /// `(hits, misses, evictions)`.
    pub fn stats(&self) -> (u64, u64, u64) {
        (self.hits, self.misses, self.evictions)
    }

    /// Pisot-drift histogram across every cached entry.
    ///
    /// Returns `(luminary_count, total_count, drift_min, drift_mean, drift_max)`.
    /// Luminary count = entries whose drift is below `luminary_threshold`.
    ///
    /// The drift surrogate `(‖x‖² − φ‖x‖ + 1).abs()` has its real-valued
    /// minimum at `‖x‖ = φ/2` where the value equals `1 − φ²/4 ≈ 0.345`.
    /// It does NOT achieve a literal zero on f32 vectors — the Lean
    /// `mitosis_restores_invariant` lives on integer Lucas pairs
    /// (`PisotMitosisManifold.lean:47`), and this f32 computation is the
    /// surrogate flagged in the `Pisot.lucas_trace_surrogate` covenant
    /// at `pisot_drift`. Pick `luminary_threshold` against the surrogate
    /// scale (e.g. `0.5` to count entries near the minimum).
    pub fn drift_summary(&self, luminary_threshold: f32) -> (u32, u32, u32, f32, f32, f32) {
        let mut total: u32 = 0;
        let mut finite: u32 = 0;
        let mut luminary: u32 = 0;
        let mut drift_min = f32::INFINITY;
        let mut drift_max = f32::NEG_INFINITY;
        let mut drift_sum = 0.0_f32;
        for bucket in self.table.values() {
            for entry in bucket.iter() {
                total += 1;
                if !entry.drift.is_finite() {
                    continue;
                }
                finite += 1;
                if entry.drift < luminary_threshold {
                    luminary += 1;
                }
                if entry.drift < drift_min {
                    drift_min = entry.drift;
                }
                if entry.drift > drift_max {
                    drift_max = entry.drift;
                }
                drift_sum += entry.drift;
            }
        }
        if finite == 0 {
            return (luminary, total, 0, 0.0, 0.0, 0.0);
        }
        let drift_mean = drift_sum / (finite as f32);
        (luminary, total, finite, drift_min, drift_mean, drift_max)
    }

    /// Per-(layer, op) breakdown. Flat-sorted by `(layer, op)` so bench
    /// output is byte-stable across runs.
    pub fn detailed_stats(&self) -> Vec<(u32, u8, u32, u32)> {
        let mut out: Vec<(u32, u8, u32, u32)> = self
            .per_key
            .iter()
            .map(|(key, (h, m))| (key.layer as u32, key.op, *h as u32, *m as u32))
            .collect();
        out.sort_by_key(|(layer, op, _, _)| (*layer, *op));
        out
    }

    /// Probe for an ER-bridge. Length-match + exact L² ≤ τ² scan over
    /// the bucket. We do NOT pre-filter by norm bucket — that produced
    /// a race with insert that gave 0 hit-rate even on bit-identical
    /// inputs (see feedback_subagent_file_collision.md). Plain exact
    /// L² scan is the contract.
    pub fn probe(
        &mut self,
        layer: usize,
        op_kind: u8,
        rows: usize,
        cols: usize,
        qtype: crate::model::QType,
        input: &[f32],
    ) -> Option<&[f32]> {
        self.probe_with_context(layer, op_kind, rows, cols, qtype, input, 0)
    }

    pub fn probe_with_context(
        &mut self,
        layer: usize,
        op_kind: u8,
        rows: usize,
        cols: usize,
        qtype: crate::model::QType,
        input: &[f32],
        context_hash: u64,
    ) -> Option<&[f32]> {
        if !self.enabled {
            return None;
        }
        self.tick = self.tick.wrapping_add(1);
        let key = MatVecMemoKey {
            layer,
            op: op_kind,
            rows,
            cols,
            qtype: qtype_tag(qtype),
            context_hash,
        };
        let tau_sq = self.tau_squared;
        let tick = self.tick;
        // We have to take a mutable borrow of the bucket so we can bump
        // `last_used` on hit. Resolve the index first, then grab the
        // reference, so the returned `&[f32]` borrow stays clean.
        let mut found_idx: Option<usize> = None;
        if let Some(bucket) = self.table.get(&key) {
            for (i, entry) in bucket.iter().enumerate() {
                if entry.input.len() != input.len() {
                    continue;
                }
                let mut acc = 0.0_f32;
                for j in 0..input.len() {
                    let d = entry.input[j] - input[j];
                    acc += d * d;
                    if acc > tau_sq {
                        break;
                    }
                }
                if acc <= tau_sq {
                    found_idx = Some(i);
                    break;
                }
            }
        }
        match found_idx {
            Some(i) => {
                self.hits += 1;
                let counter = self.per_key.entry(key).or_insert((0, 0));
                counter.0 += 1;
                let bucket = self.table.get_mut(&key).expect("bucket vanished mid-probe");
                bucket[i].last_used = tick;
                bucket[i].hit_count = bucket[i].hit_count.saturating_add(1);
                Some(&bucket[i].output)
            }
            None => {
                self.misses += 1;
                let counter = self.per_key.entry(key).or_insert((0, 0));
                counter.1 += 1;
                None
            }
        }
    }

    /// Insert a fresh `(input, output)` pair. Clones `input`, consumes
    /// `output`. On capacity, evicts the entry maximizing
    /// `drift × age`.
    pub fn insert(
        &mut self,
        layer: usize,
        op_kind: u8,
        rows: usize,
        cols: usize,
        qtype: crate::model::QType,
        input: &[f32],
        output: Vec<f32>,
    ) {
        self.insert_with_context(layer, op_kind, rows, cols, qtype, input, output, 0);
    }

    pub fn insert_with_context(
        &mut self,
        layer: usize,
        op_kind: u8,
        rows: usize,
        cols: usize,
        qtype: crate::model::QType,
        input: &[f32],
        output: Vec<f32>,
        context_hash: u64,
    ) {
        if !self.enabled {
            return;
        }
        self.tick = self.tick.wrapping_add(1);
        let tick = self.tick;

        if self.total_entries >= self.max_entries && self.max_entries > 0 {
            self.evict_one(tick);
        }

        let drift = pisot_drift(input);
        let entry = MatVecMemoEntry {
            input: input.to_vec(),
            output,
            drift,
            last_used: tick,
            hit_count: 0,
        };
        let key = MatVecMemoKey {
            layer,
            op: op_kind,
            rows,
            cols,
            qtype: qtype_tag(qtype),
            context_hash,
        };
        let bucket = self.table.entry(key).or_default();
        bucket.push(entry);
        self.total_entries += 1;
    }

    /// Walk every bucket, find the entry with the lowest liquid-memory density
    /// score: `density = (key.rows × key.cols) × (entry.hit_count + 1)`.
    /// LRU (`last_used`) breaks ties — older entries are evicted first.
    /// Accumulates the evicted density into `heat_released`.
    fn evict_one(&mut self, _now: u64) {
        // victim: (key, bucket_index, density, last_used)
        let mut victim: Option<(MatVecMemoKey, usize, u64, u64)> = None;
        for (key, bucket) in self.table.iter() {
            let recompute_cost = (key.rows as u64).saturating_mul(key.cols as u64);
            for (i, entry) in bucket.iter().enumerate() {
                let density = recompute_cost.saturating_mul(entry.hit_count as u64 + 1);
                let take = match victim {
                    None => true,
                    Some((_, _, best_density, best_last_used)) => {
                        density < best_density
                            || (density == best_density && entry.last_used < best_last_used)
                    }
                };
                if take {
                    victim = Some((*key, i, density, entry.last_used));
                }
            }
        }
        if let Some((key, idx, density, _)) = victim {
            if let Some(bucket) = self.table.get_mut(&key) {
                bucket.swap_remove(idx);
                if bucket.is_empty() {
                    self.table.remove(&key);
                }
            }
            self.total_entries = self.total_entries.saturating_sub(1);
            self.evictions += 1;
            self.heat_released = self.heat_released.saturating_add(density);
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn eviction_uses_full_shape_key() {
        let mut memo = MatVecMemo::new();
        memo.set_enabled(true);
        memo.set_max_entries(1);

        memo.insert(
            7,
            2,
            3,
            4,
            crate::model::QType::F32,
            &[1.0, 0.0, 0.0, 0.0],
            vec![1.0, 2.0, 3.0],
        );
        memo.insert(
            7,
            2,
            5,
            4,
            crate::model::QType::F32,
            &[0.0, 1.0, 0.0, 0.0],
            vec![4.0, 5.0, 6.0, 7.0, 8.0],
        );

        let (_, _, evictions) = memo.stats();
        assert_eq!(evictions, 1);
        assert_eq!(memo.total_entries, 1);
        assert_eq!(memo.table.values().map(Vec::len).sum::<usize>(), 1);
    }

    fn raw_f32_batch(
        out: &mut [f32],
        x: &[f32],
        w: &[f32],
        rows: usize,
        cols: usize,
        n_batch: usize,
        out_stride: usize,
    ) {
        for b in 0..n_batch {
            let x_row = &x[b * cols..b * cols + cols];
            let out_row = &mut out[b * out_stride..b * out_stride + rows];
            for r in 0..rows {
                let mut acc = 0.0_f32;
                for c in 0..cols {
                    acc += w[r * cols + c] * x_row[c];
                }
                out_row[r] = acc;
            }
        }
    }

    #[test]
    fn context_hash_keeps_f32_attention_prefixes_distinct() {
        let mut memo = MatVecMemo::new();
        memo.set_enabled(true);
        memo.set_tau_squared(0.0);

        let x = [1.0_f32, 2.0];
        let w = [1.0_f32, 0.0, 0.0, 1.0];
        let mut out = [0.0_f32; 2];
        cached_mat_vec_f32_with_context(
            &mut memo,
            &mut out,
            &x,
            &w,
            2,
            2,
            1,
            2,
            0,
            OP_ATTENTION_SCORE,
            11,
            raw_f32_batch,
        );
        assert_eq!(out, [1.0, 2.0]);

        let w_changed = [10.0_f32, 0.0, 0.0, 10.0];
        let mut miss_out = [0.0_f32; 2];
        cached_mat_vec_f32_with_context(
            &mut memo,
            &mut miss_out,
            &x,
            &w_changed,
            2,
            2,
            1,
            2,
            0,
            OP_ATTENTION_SCORE,
            22,
            raw_f32_batch,
        );
        assert_eq!(miss_out, [10.0, 20.0]);
        assert_eq!(memo.stats(), (0, 2, 0));

        let mut hit_out = [0.0_f32; 2];
        cached_mat_vec_f32_with_context(
            &mut memo,
            &mut hit_out,
            &x,
            &w_changed,
            2,
            2,
            1,
            2,
            0,
            OP_ATTENTION_SCORE,
            22,
            raw_f32_batch,
        );
        assert_eq!(hit_out, [10.0, 20.0]);
        assert_eq!(memo.stats(), (1, 2, 0));
    }

    #[test]
    fn cached_f32_weight_matvec_reuses_identical_batch_input() {
        let mut memo = MatVecMemo::new();
        memo.set_enabled(true);
        memo.set_tau_squared(0.0);

        let x = [1.0_f32, 2.0, 3.0, 4.0];
        let w = [1.0_f32, 0.0, 0.5, 0.5];
        let mut out = [0.0_f32; 4];
        cached_mat_vec_f32(
            &mut memo,
            &mut out,
            &x,
            &w,
            2,
            2,
            2,
            2,
            3,
            OP_OUTPUT_PROJ,
            raw_f32_batch,
        );
        assert_eq!(out, [1.0, 1.5, 3.0, 3.5]);

        let w_changed = [100.0_f32; 4];
        let mut hit_out = [0.0_f32; 4];
        cached_mat_vec_f32(
            &mut memo,
            &mut hit_out,
            &x,
            &w_changed,
            2,
            2,
            2,
            2,
            3,
            OP_OUTPUT_PROJ,
            raw_f32_batch,
        );
        assert_eq!(hit_out, out);
        assert_eq!(memo.stats(), (1, 1, 0));
    }
}

impl Default for MatVecMemo {
    fn default() -> Self {
        Self::new()
    }
}

// ───────────────────── pisot drift surrogate ─────────────────────
// `(‖x‖² − φ‖x‖ + 1).abs()`. Vanishes when ‖x‖ is on the unit circle of
// the golden polynomial — i.e. the state lives near a Pisot-stable
// attractor. We use ‖x‖² as the squared norm to skip a sqrt where we
// can; the closed form keeps `‖x‖`, so we still pay one sqrt per
// insert. This is fine: insert is the cold path.
// COVENANT: Lean theorem `Pisot.lucas_trace_surrogate` (unwritten) —
// equivalence to the proper Lucas-trace minimal polynomial residual.
pub fn pisot_drift(x: &[f32]) -> f32 {
    let mut n2 = 0.0_f32;
    for &v in x {
        n2 += v * v;
    }
    let n = n2.sqrt();
    (n2 - PHI * n + 1.0).abs()
}

#[inline]
pub fn hash_f32_slice_bits(values: &[f32]) -> u64 {
    let mut hash = 0xcbf2_9ce4_8422_2325_u64;
    for value in values {
        hash ^= value.to_bits() as u64;
        hash = hash.wrapping_mul(0x0000_0100_0000_01b3);
    }
    hash
}

#[inline]
pub fn hash_bytes(values: &[u8]) -> u64 {
    let mut hash = 0xcbf2_9ce4_8422_2325_u64;
    for value in values {
        hash ^= *value as u64;
        hash = hash.wrapping_mul(0x0000_0100_0000_01b3);
    }
    hash
}

#[inline(always)]
fn qtype_tag(qtype: crate::model::QType) -> u8 {
    match qtype {
        crate::model::QType::F32 => 0,
        crate::model::QType::Q4K => 1,
        crate::model::QType::Q5_0 => 2,
        crate::model::QType::Q5K => 3,
        crate::model::QType::Q6K => 4,
        crate::model::QType::Q8_0 => 5,
        crate::model::QType::F16 => 6,
        crate::model::QType::IQ2S => 7,
        crate::model::QType::IQ3S => 8,
        crate::model::QType::KAIJU1 => 9,
    }
}

// ───────────────────────── cached_mat_vec ─────────────────────────
/// Wraps `mat_vec_dispatch_batch` with probe-first / insert-on-miss.
///
/// `raw_dispatch` is the foreground integration step's reference to
/// `crate::model::mat_vec_dispatch_batch`. We take it as a `fn`
/// pointer so this module never imports `model.rs` — keeping the
/// dependency direction one-way (model → memo, never memo → model).
///
/// SHAPE CONTRACT:
///   - `x` is `n_batch` rows of `cols` floats, contiguous.
///   - `out` is `n_batch` rows of `out_stride` floats, where only the
///     first `rows` of each row are written.
///   - The cache stores OUTPUT in COMPACT form (`n_batch × rows`, no
///     stride padding). On hit we re-stride into the caller's `out`;
///     on miss we capture the compact bytes back from `out` after the
///     dispatch writes them.
#[inline]
pub fn cached_mat_vec(
    memo: &mut MatVecMemo,
    out: &mut [f32],
    x: &[f32],
    w: &[u8],
    qtype: crate::model::QType,
    rows: usize,
    cols: usize,
    n_batch: usize,
    out_stride: usize,
    layer: usize,
    op: u8,
    raw_dispatch: fn(&mut [f32], &[f32], &[u8], crate::model::QType, usize, usize, usize, usize),
) {
    if n_batch == 0 {
        return;
    }
    // Memo disabled (the serving default): straight dispatch, no probe, no
    // compact capture. Without this, every matvec paid a full-output
    // Vec build + memcpy feeding an insert that no-ops — ~5.5 MB of
    // alloc+copy per decode token on a 7B (7 projections × 32 layers).
    if !memo.is_enabled() {
        raw_dispatch(out, x, w, qtype, rows, cols, n_batch, out_stride);
        return;
    }
    let probe_slice = &x[..n_batch * cols];

    // Fast path: probe. `out` is disjoint from `memo`, so we can re-stride
    // the cached payload while the probe borrow is live — no clone.
    if let Some(cached) = memo.probe(layer, op, rows, cols, qtype, probe_slice) {
        // Cached output is compact `n_batch × rows`. Re-stride into
        // `out` (which is `n_batch × out_stride`).
        for b in 0..n_batch {
            let src = &cached[b * rows..b * rows + rows];
            let dst = &mut out[b * out_stride..b * out_stride + rows];
            dst.copy_from_slice(src);
        }
        return;
    }

    // Miss: compute, then capture compact output back from `out`.
    raw_dispatch(out, x, w, qtype, rows, cols, n_batch, out_stride);

    let mut compact = Vec::with_capacity(n_batch * rows);
    for b in 0..n_batch {
        let row = &out[b * out_stride..b * out_stride + rows];
        compact.extend_from_slice(row);
    }
    memo.insert(layer, op, rows, cols, qtype, probe_slice, compact);
}

/// F32-weight variant of [`cached_mat_vec`].
///
/// This is for paths whose loader has already materialized weights as
/// `&[f32]` (fp32 borrow-through or fp16 dequant). The operation identity
/// still comes from `(layer, op, rows, cols, F32)`, so callers must use stable
/// per-weight op IDs exactly like quantized callers do.
#[inline]
pub fn cached_mat_vec_f32(
    memo: &mut MatVecMemo,
    out: &mut [f32],
    x: &[f32],
    w: &[f32],
    rows: usize,
    cols: usize,
    n_batch: usize,
    out_stride: usize,
    layer: usize,
    op: u8,
    raw_dispatch: fn(&mut [f32], &[f32], &[f32], usize, usize, usize, usize),
) {
    if n_batch == 0 {
        return;
    }
    // Memo disabled: straight dispatch — skip probe + compact capture.
    if !memo.is_enabled() {
        raw_dispatch(out, x, w, rows, cols, n_batch, out_stride);
        return;
    }
    let probe_slice = &x[..n_batch * cols];

    if let Some(cached) = memo.probe(layer, op, rows, cols, crate::model::QType::F32, probe_slice)
    {
        for b in 0..n_batch {
            let src = &cached[b * rows..b * rows + rows];
            let dst = &mut out[b * out_stride..b * out_stride + rows];
            dst.copy_from_slice(src);
        }
        return;
    }

    raw_dispatch(out, x, w, rows, cols, n_batch, out_stride);

    let mut compact = Vec::with_capacity(n_batch * rows);
    for b in 0..n_batch {
        let row = &out[b * out_stride..b * out_stride + rows];
        compact.extend_from_slice(row);
    }
    memo.insert(
        layer,
        op,
        rows,
        cols,
        crate::model::QType::F32,
        probe_slice,
        compact,
    );
}

/// F32 memo wrapper with an extra caller-provided context discriminator.
///
/// This is for dynamic "weights" such as attention K-prefix slabs. The same
/// query vector at the same layer/head/position is not enough to prove a hit:
/// the prefix itself must match. Callers pass a hash of the relevant K slab so
/// exact repeated prefixes can skip while different prefixes cannot alias.
#[inline]
pub fn cached_mat_vec_f32_with_context(
    memo: &mut MatVecMemo,
    out: &mut [f32],
    x: &[f32],
    w: &[f32],
    rows: usize,
    cols: usize,
    n_batch: usize,
    out_stride: usize,
    layer: usize,
    op: u8,
    context_hash: u64,
    raw_dispatch: fn(&mut [f32], &[f32], &[f32], usize, usize, usize, usize),
) {
    if n_batch == 0 {
        return;
    }
    // Memo disabled: straight dispatch — skip probe + compact capture.
    if !memo.is_enabled() {
        raw_dispatch(out, x, w, rows, cols, n_batch, out_stride);
        return;
    }
    let probe_slice = &x[..n_batch * cols];

    if let Some(cached) = memo.probe_with_context(
        layer,
        op,
        rows,
        cols,
        crate::model::QType::F32,
        probe_slice,
        context_hash,
    ) {
        for b in 0..n_batch {
            let src = &cached[b * rows..b * rows + rows];
            let dst = &mut out[b * out_stride..b * out_stride + rows];
            dst.copy_from_slice(src);
        }
        return;
    }

    raw_dispatch(out, x, w, rows, cols, n_batch, out_stride);

    let mut compact = Vec::with_capacity(n_batch * rows);
    for b in 0..n_batch {
        let row = &out[b * out_stride..b * out_stride + rows];
        compact.extend_from_slice(row);
    }
    memo.insert_with_context(
        layer,
        op,
        rows,
        cols,
        crate::model::QType::F32,
        probe_slice,
        compact,
        context_hash,
    );
}
